"use strict";(self.webpackChunksysanalyst_kb=self.webpackChunksysanalyst_kb||[]).push([["22274"],{19041(i){i.exports=JSON.parse('{"tag":{"label":"telecom","permalink":"/sysanalyst-kb.github.io/docs/tags/telecom","allTagsPath":"/sysanalyst-kb.github.io/docs/tags","count":8,"items":[{"id":"specialization/telecom-5g-iot","title":"5G, IoT \u0438 \u043D\u043E\u0432\u044B\u0435 \u0442\u0435\u0445\u043D\u043E\u043B\u043E\u0433\u0438\u0438 \u0432 Telecom","description":"5G \u2014 \u043D\u0435 \u043F\u0440\u043E\u0441\u0442\u043E \xab\u0431\u044B\u0441\u0442\u0440\u0435\u0435\xbb, \u0430 \u043D\u043E\u0432\u0430\u044F \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u0430 B2B-\u0441\u0435\u0442\u044C \u0434\u043B\u044F \u0437\u0430\u0432\u043E\u0434\u043E\u0432, IoT-\u0442\u0430\u0440\u0438\u0444\u044B \u0434\u043B\u044F \u043C\u0438\u043B\u043B\u0438\u043E\u043D\u043E\u0432 \u0443\u0441\u0442\u0440\u043E\u0439\u0441\u0442\u0432, SLA \u043D\u0430 \u0443\u0440\u043E\u0432\u043D\u0435 \u0441\u0435\u0442\u0438.","permalink":"/sysanalyst-kb.github.io/docs/specialization/telecom-5g-iot"},{"id":"specialization/telecom-billing","title":"Billing \u0438 Charging \u2014 \u0442\u0430\u0440\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u044F \u0432 Telecom","description":"Billing (\u0432\u044B\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u0435 \u0441\u0447\u0435\u0442\u043E\u0432) \u0438 Charging (\u0442\u0430\u0440\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u044F \u0432 \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u043C \u0432\u0440\u0435\u043C\u0435\u043D\u0438) \u2014 \u044F\u0434\u0440\u043E Telecom. Pre-paid \u0441\u0447\u0451\u0442 \u0432 \u043A\u043E\u043D\u0446\u0435 \u043C\u0435\u0441\u044F\u0446\u0430. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u0446\u0438\u0440\u0443\u0435\u0442 \u0442\u0430\u0440\u0438\u0444\u043D\u044B\u0435 \u043F\u043B\u0430\u043D\u044B, CDR (Call Data Records), \u0440\u043E\u0443\u043C\u0438\u043D\u0433, OCS (Online Charging System) \u0438 \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u044E \u0441 CRM.","permalink":"/sysanalyst-kb.github.io/docs/specialization/telecom-billing"},{"id":"specialization/telecom-bss-oss","title":"BSS/OSS \u2014 \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u0430 Telecom-\u0441\u0438\u0441\u0442\u0435\u043C","description":"\u0410\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u0430 Telecom \u0434\u0435\u043B\u0438\u0442\u0441\u044F \u043D\u0430 BSS (Business Support Systems) \u0438 OSS (Operations Support Systems). BSS \u043E\u0442\u0432\u0435\u0447\u0430\u0435\u0442 \u0437\u0430 \u0430\u0431\u043E\u043D\u0435\u043D\u0442\u043E\u0432, \u0442\u0430\u0440\u0438\u0444\u044B, \u0431\u0438\u043B\u043B\u0438\u043D\u0433, \u0437\u0430\u043A\u0430\u0437\u044B. OSS \u2014 \u0437\u0430 \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u0438\u0435 \u0441\u0435\u0442\u0438, \u0430\u043A\u0442\u0438\u0432\u0430\u0446\u0438\u044E \u0443\u0441\u043B\u0443\u0433 \u0438 \u043C\u043E\u043D\u0438\u0442\u043E\u0440\u0438\u043D\u0433. \u0421\u0442\u0430\u043D\u0434\u0430\u0440\u0442\u044B: TM Forum (eTOM, SID, TAM, Open API).","permalink":"/sysanalyst-kb.github.io/docs/specialization/telecom-bss-oss"},{"id":"specialization/telecom-crm-order","title":"CRM \u0438 Order Management \u0432 Telecom","description":"CRM \u0432 Telecom \u2014 \u043D\u0435 \u043F\u0440\u043E\u0441\u0442\u043E \u043A\u043E\u043D\u0442\u0430\u043A\u0442\u044B, \u0430 \u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0435 \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u044B\u043C \u0446\u0438\u043A\u043B\u043E\u043C \u0430\u0431\u043E\u043D\u0435\u043D\u0442\u0430: \u0440\u0435\u0433\u0438\u0441\u0442\u0440\u0430\u0446\u0438\u044F, \u0441\u043C\u0435\u043D\u0430 \u0442\u0430\u0440\u0438\u0444\u0430, \u0431\u043B\u043E\u043A\u0438\u0440\u043E\u0432\u043A\u0430, \u043E\u0442\u043A\u043B\u044E\u0447\u0435\u043D\u0438\u0435, MNP (\u043F\u0435\u0440\u0435\u043D\u043E\u0441 \u043D\u043E\u043C\u0435\u0440\u0430). Order Management \u2014 \u0437\u0430\u043A\u0430\u0437\u044B \u043D\u0430 \u0443\u0441\u043B\u0443\u0433\u0438, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0438\u0434\u0443\u0442 \u0432 Provisioning \u0438 \u0434\u0430\u043B\u0435\u0435 \u0432 \u0441\u0435\u0442\u044C.","permalink":"/sysanalyst-kb.github.io/docs/specialization/telecom-crm-order"},{"id":"specialization/telecom-mvno","title":"MVNO \u2014 \u043C\u043E\u0434\u0435\u043B\u044C \u0432\u0438\u0440\u0442\u0443\u0430\u043B\u044C\u043D\u044B\u0445 \u043E\u043F\u0435\u0440\u0430\u0442\u043E\u0440\u043E\u0432","description":"MVNO (Mobile Virtual Network Operator) \u2014 \u043E\u043F\u0435\u0440\u0430\u0442\u043E\u0440 \u0431\u0435\u0437 \u0441\u0432\u043E\u0435\u0439 \u0441\u0435\u0442\u0438. \u0410\u0440\u0435\u043D\u0434\u0443\u0435\u0442 \u0438\u043D\u0444\u0440\u0430\u0441\u0442\u0440\u0443\u043A\u0442\u0443\u0440\u0443 \u0443 MNO (\u0445\u043E\u0441\u0442-\u043E\u043F\u0435\u0440\u0430\u0442\u043E\u0440\u0430). \u0412\u0438\u0440\u0442\u0443\u0430\u043B\u044C\u043D\u044B\u0439 \u043E\u043F\u0435\u0440\u0430\u0442\u043E\u0440 \u0441\u0430\u043C \u0443\u043F\u0440\u0430\u0432\u043B\u044F\u0435\u0442 \u0442\u0430\u0440\u0438\u0444\u0430\u043C\u0438, \u0431\u0438\u043B\u043B\u0438\u043D\u0433\u043E\u043C, \u043C\u0430\u0440\u043A\u0435\u0442\u0438\u043D\u0433\u043E\u043C, \u043D\u043E \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0435\u0442 \u0441\u0435\u0442\u044C \u0438 \u043D\u0443\u043C\u0435\u0440\u0430\u0446\u0438\u044E MNO. \u041F\u0440\u0438\u043C\u0435\u0440\u044B: Yota (MVNO \u043D\u0430 \u041C\u0435\u0433\u0430\u0444\u043E\u043D), \u0422\u0438\u043D\u044C\u043A\u043E\u0444\u0444 \u041C\u043E\u0431\u0430\u0439\u043B, Virgin Mobile.","permalink":"/sysanalyst-kb.github.io/docs/specialization/telecom-mvno"},{"id":"specialization/telecom-provisioning","title":"Provisioning \u0438 \u0430\u043A\u0442\u0438\u0432\u0430\u0446\u0438\u044F \u0443\u0441\u043B\u0443\u0433","description":"Provisioning \u2014 \u043C\u043E\u0441\u0442 \u043C\u0435\u0436\u0434\u0443 BSS \u0438 \u0441\u0435\u0442\u044C\u044E. \u041F\u043E\u043B\u0443\u0447\u0430\u0435\u0442 \u0437\u0430\u043A\u0430\u0437 \u0438\u0437 Order Management \u0438 \u043A\u043E\u043D\u0444\u0438\u0433\u0443\u0440\u0438\u0440\u0443\u0435\u0442 \u0441\u0435\u0442\u0435\u0432\u043E\u0435 \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u0438\u0435: HLR/HSS (\u0433\u043E\u043B\u043E\u0441), PGW/GGSN (\u0434\u0430\u043D\u043D\u044B\u0435), OCS (\u0442\u0430\u0440\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u044F). \u0411\u0435\u0437 Provisioning \u0430\u0431\u043E\u043D\u0435\u043D\u0442 \u043D\u0435 \u043F\u043E\u043B\u0443\u0447\u0438\u0442 \u0443\u0441\u043B\u0443\u0433\u0443.","permalink":"/sysanalyst-kb.github.io/docs/specialization/telecom-provisioning"},{"id":"specialization/telecom-path","title":"Telecom \u2014 \u0440\u043E\u043B\u044C, \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u043A\u0430, \u043A\u0430\u0440\u044C\u0435\u0440\u043D\u044B\u0439 \u043F\u0443\u0442\u044C","description":"Telecom-\u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442 \u0441 BSS/OSS \u2014 \u0441\u0438\u0441\u0442\u0435\u043C\u0430\u043C\u0438 \u0434\u043B\u044F \u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u044F \u0430\u0431\u043E\u043D\u0435\u043D\u0442\u0430\u043C\u0438, \u0442\u0430\u0440\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u0438, \u0437\u0430\u043A\u0430\u0437\u0430\u043C\u0438 \u0438 \u0441\u0435\u0442\u044C\u044E. \u0421\u043F\u0435\u0446\u0438\u0444\u0438\u043A\u0430: \u043C\u0438\u043B\u043B\u0438\u043E\u043D\u044B \u0430\u0431\u043E\u043D\u0435\u043D\u0442\u043E\u0432, real-time charging, \u0436\u0451\u0441\u0442\u043A\u0430\u044F \u0440\u0435\u0433\u0443\u043B\u044F\u0446\u0438\u044F (\u0421\u041E\u0420\u041C, 152-\u0424\u0417, \u043B\u0438\u0446\u0435\u043D\u0437\u0438\u0438) \u0438 \u0434\u043B\u0438\u043D\u043D\u044B\u0439 lifecycle (\u0434\u0435\u0441\u044F\u0442\u0438\u043B\u0435\u0442\u0438\u044F\u043C\u0438 \u0440\u0430\u0431\u043E\u0442\u0430\u044E\u0449\u0438\u0435 legacy-\u0441\u0438\u0441\u0442\u0435\u043C\u044B).","permalink":"/sysanalyst-kb.github.io/docs/specialization/telecom-path"},{"id":"specialization/telecom-regulations","title":"\u0420\u0435\u0433\u0443\u043B\u044F\u0442\u043E\u0440\u0438\u043A\u0430 \u0432 Telecom (\u0421\u041E\u0420\u041C, \u041F\u0414, \u043B\u0438\u0446\u0435\u043D\u0437\u0438\u0438)","description":"Telecom \u2014 \u043E\u0434\u043D\u0430 \u0438\u0437 \u0441\u0430\u043C\u044B\u0445 \u0440\u0435\u0433\u0443\u043B\u0438\u0440\u0443\u0435\u043C\u044B\u0445 \u043E\u0442\u0440\u0430\u0441\u043B\u0435\u0439. \u041A\u043B\u044E\u0447\u0435\u0432\u044B\u0435 \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043D\u0438\u044F: \u0421\u041E\u0420\u041C (\u0434\u043E\u0441\u0442\u0443\u043F \u043F\u0440\u0430\u0432\u043E\u043E\u0445\u0440\u0430\u043D\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u0445 \u043E\u0440\u0433\u0430\u043D\u043E\u0432 \u043A \u0442\u0440\u0430\u0444\u0438\u043A\u0443), 152-\u0424\u0417 (\u043F\u0435\u0440\u0441\u043E\u043D\u0430\u043B\u044C\u043D\u044B\u0435 \u0434\u0430\u043D\u043D\u044B\u0435), \u043B\u0438\u0446\u0435\u043D\u0437\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435 \u0443\u0441\u043B\u0443\u0433 \u0441\u0432\u044F\u0437\u0438, MNP (\u043F\u0435\u0440\u0435\u043D\u043E\u0441\u0438\u043C\u043E\u0441\u0442\u044C \u043D\u043E\u043C\u0435\u0440\u0430), anti-fraud \u0438 \u0431\u043B\u043E\u043A\u0438\u0440\u043E\u0432\u043A\u0430 \u0437\u0430\u043F\u0440\u0435\u0449\u0451\u043D\u043D\u044B\u0445 \u0440\u0435\u0441\u0443\u0440\u0441\u043E\u0432 (\u0420\u041A\u041D).","permalink":"/sysanalyst-kb.github.io/docs/specialization/telecom-regulations"}],"unlisted":false}}')}}]);